selector_to_html = {"a[href=\"#sistema-no-amortiguado-zeta-0\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema no amortiguado (<span class=\"math notranslate nohighlight\">\\(\\zeta = 0\\)</span>)<a class=\"headerlink\" href=\"#sistema-no-amortiguado-zeta-0\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#equation-785a8259-3f74-4692-97a5-4874d2a833d4\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-785a8259-3f74-4692-97a5-4874d2a833d4\">\n\\[\\begin{equation}\n x(t) = A\\cos(\\omega_n t) + B\\sin(\\omega_n t).\n\\end{equation}\\]</div>", "a[href=\"#equation-684ec001-9702-4818-be21-129fe35be21c\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-684ec001-9702-4818-be21-129fe35be21c\">\n\\[\\begin{equation}\n m\\frac{d^2x}{dt^2} + c\\frac{dx}{dt} + kx = 0,\n\\end{equation}\\]</div>", "a[href=\"#equation-f68055f7-f7e8-4610-a749-831bb6a62177\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-f68055f7-f7e8-4610-a749-831bb6a62177\">\n\\[\\begin{equation}\n \\omega_d = \\omega_n\\sqrt{1-\\zeta^2} \\quad \\text{(para } \\zeta &lt; 1\\text{)}.\n\\end{equation}\\]</div>", "a[href=\"#sistema-con-amortiguamiento-critico-zeta-1\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema con amortiguamiento cr\u00edtico (<span class=\"math notranslate nohighlight\">\\(\\zeta = 1\\)</span>)<a class=\"headerlink\" href=\"#sistema-con-amortiguamiento-critico-zeta-1\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#sistema-masa-resorte-amortiguador\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema masa resorte amortiguador<a class=\"headerlink\" href=\"#sistema-masa-resorte-amortiguador\" title=\"Link to this heading\">#</a></h1><p>Un <strong>sistema masa resorte amortiguador</strong> consta de tres componentes esenciales</p>", "a[href=\"#equation-9d03bc3d-74f2-4b8a-8fc6-a58d45544e7f\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-9d03bc3d-74f2-4b8a-8fc6-a58d45544e7f\">\n\\[\\begin{equation}\n E(t) = \\underbrace{\\frac{1}{2}m\\dot{x}^2}_{\\text{Cin\u00e9tica}} + \\underbrace{\\frac{1}{2}kx^2}_{\\text{Potencial}} + \\underbrace{\\int_0^t c\\dot{x}^2\\,dt}_{\\text{Disipada}}\n\\end{equation}\\]</div>", "a[href=\"#equation-8ceb8e58-98f9-45fe-a15d-f861e922765b\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-8ceb8e58-98f9-45fe-a15d-f861e922765b\">\n\\[\\begin{equation}\n x(t) = Ae^{\\lambda_1 t} + Be^{\\lambda_2 t}.\n\\end{equation}\\]</div>", "a[href=\"#equation-0fc1dabd-62ae-48f9-8ebc-6122653f4ed5\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-0fc1dabd-62ae-48f9-8ebc-6122653f4ed5\">\n\\[\\begin{equation}\n \\zeta = \\frac{c}{2\\sqrt{km}}.\n\\end{equation}\\]</div>", "a[href=\"#ejemplo-de-parametros-de-simulacion\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Ejemplo de Par\u00e1metros de Simulaci\u00f3n<a class=\"headerlink\" href=\"#ejemplo-de-parametros-de-simulacion\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#equation-47a94531-645f-4a5e-8012-94870c7546e3\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-47a94531-645f-4a5e-8012-94870c7546e3\">\n\\[\\begin{equation}\n x(t) = (A + Bt)e^{-\\omega_n t}.\n\\end{equation}\\]</div>", "a[href=\"#parametros-adimensionales\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Par\u00e1metros adimensionales<a class=\"headerlink\" href=\"#parametros-adimensionales\" title=\"Link to this heading\">#</a></h3><p><strong>Frecuencia Natural</strong></p>", "a[href=\"#componentes-de-fuerza\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Componentes de Fuerza<a class=\"headerlink\" href=\"#componentes-de-fuerza\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#sistema-sobreamortiguado-zeta-1\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema sobreamortiguado (<span class=\"math notranslate nohighlight\">\\(\\zeta &gt; 1\\)</span>)<a class=\"headerlink\" href=\"#sistema-sobreamortiguado-zeta-1\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#modelo-matematico\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Modelo Matem\u00e1tico<a class=\"headerlink\" href=\"#modelo-matematico\" title=\"Link to this heading\">#</a></h2><h3>Ecuaci\u00f3n diferencial gobernante<a class=\"headerlink\" href=\"#ecuacion-diferencial-gobernante\" title=\"Link to this heading\">#</a></h3><p>El sistema se rige por la segunda Ley de Newton</p>", "a[href=\"#tipos-de-solucion-segun-la-razon-de-amortiguamiento\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Tipos de soluci\u00f3n seg\u00fan la raz\u00f3n de amortiguamiento<a class=\"headerlink\" href=\"#tipos-de-solucion-segun-la-razon-de-amortiguamiento\" title=\"Link to this heading\">#</a></h2><h3>Sistema no amortiguado (<span class=\"math notranslate nohighlight\">\\(\\zeta = 0\\)</span>)<a class=\"headerlink\" href=\"#sistema-no-amortiguado-zeta-0\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#sistema-subamortiguado-0-zeta-1\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema subamortiguado (<span class=\"math notranslate nohighlight\">\\(0 &lt; \\zeta &lt; 1\\)</span>)<a class=\"headerlink\" href=\"#sistema-subamortiguado-0-zeta-1\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#interpretacion-fisica\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Interpretaci\u00f3n F\u00edsica<a class=\"headerlink\" href=\"#interpretacion-fisica\" title=\"Link to this heading\">#</a></h2><h3>Balance de Energ\u00eda<a class=\"headerlink\" href=\"#balance-de-energia\" title=\"Link to this heading\">#</a></h3><p><strong>Energ\u00eda Total = Energ\u00eda Cin\u00e9tica + Energ\u00eda Potencial + Energ\u00eda Disipada</strong></p>", "a[href=\"#equation-ddac2f9d-e8a5-4d23-a82a-ef27c8b1b3ea\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-ddac2f9d-e8a5-4d23-a82a-ef27c8b1b3ea\">\n\\[\\begin{equation}\n x(t) = e^{-\\zeta\\omega_n t}\\left[A\\cos(\\omega_d t) + B\\sin(\\omega_d t)\\right].\n\\end{equation}\\]</div>", "a[href=\"#superposicion-del-modelo-clasico-y-el-modelo-conformable\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Superposici\u00f3n del modelo cl\u00e1sico y el modelo conformable<a class=\"headerlink\" href=\"#superposicion-del-modelo-clasico-y-el-modelo-conformable\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#equation-3b99c407-5979-4b58-beb1-1bdd830c321f\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-3b99c407-5979-4b58-beb1-1bdd830c321f\">\n\\[\\begin{equation}\n \\lambda_{1,2} = -\\frac{c}{2m} \\pm \\sqrt{\\left(\\frac{c}{2m}\\right)^2 - \\frac{k}{m}}.\n\\end{equation}\\]</div>", "a[href=\"#equation-b16185d6-c336-4bfb-b32e-8a2dd8b1b16e\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-b16185d6-c336-4bfb-b32e-8a2dd8b1b16e\">\n\\[\\begin{equation}\n m\\lambda^2 + c\\lambda + k = 0,\n\\end{equation}\\]</div>", "a[href=\"#balance-de-energia\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Balance de Energ\u00eda<a class=\"headerlink\" href=\"#balance-de-energia\" title=\"Link to this heading\">#</a></h3><p><strong>Energ\u00eda Total = Energ\u00eda Cin\u00e9tica + Energ\u00eda Potencial + Energ\u00eda Disipada</strong></p>", "a[href=\"#ecuacion-caracteristica-del-sistema\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Ecuaci\u00f3n caracter\u00edstica del sistema<a class=\"headerlink\" href=\"#ecuacion-caracteristica-del-sistema\" title=\"Link to this heading\">#</a></h3><p>Al sustituir <span class=\"math notranslate nohighlight\">\\(x(t) = e^{\\lambda t}\\)</span> se obtiene:</p>", "a[href=\"#ecuacion-diferencial-gobernante\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Ecuaci\u00f3n diferencial gobernante<a class=\"headerlink\" href=\"#ecuacion-diferencial-gobernante\" title=\"Link to this heading\">#</a></h3><p>El sistema se rige por la segunda Ley de Newton</p>", "a[href=\"#equation-89168751-94d7-4104-946e-5f1a46f64fc5\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-89168751-94d7-4104-946e-5f1a46f64fc5\">\n\\[\\begin{equation}\n \\omega_n = \\sqrt{\\frac{k}{m}} \\quad \\text{[rad/s]}.\n\\end{equation}\\]</div>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(`article.bd-article ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: false,
                placement: 'auto-start', maxWidth: 500, interactive: true, boundary: document.body, appendTo: document.body,
                onShow(instance) {MathJax.typesetPromise([instance.popper]).then(() => {var isFirefox=typeof InstallTrigger!=='undefined';if(isFirefox&&window.MathJax&&MathJax.startup&&MathJax.startup.output&&MathJax.startup.output.name==="SVG"){const svgs=instance.popper.querySelectorAll('svg');svgs.forEach(svg=>{let bbox=svg.getBBox(),x=bbox.x,y=bbox.y,width=bbox.width,height=bbox.height;svg.setAttribute('width',width);svg.setAttribute('height',height);svg.setAttribute('viewBox',`${x} ${y} ${width} ${height}`);});let rescale=0.015;svgs.forEach(svg=>{let bbox=svg.getBBox(),width=bbox.width,height=bbox.height;svg.setAttribute('width',width*rescale);svg.setAttribute('height',height*rescale);});}});},
            });
        };
    };
    console.log("tippy tips loaded!");
};
